import Link from "next/link";

import { ProductCard } from "@/components/ui/ProductCard";
import { getServerLanguage } from "@/lib/server-language";
import {
  getActiveCategories,
  searchActiveProducts,
} from "@/lib/storefront-data";
import { getMessages } from "@/lib/storefront";

export const dynamic = "force-dynamic";

type ProductsPageProps = {
  searchParams: Promise<{
    q?: string | string[];
    category?: string | string[];
  }>;
};

function readParam(value?: string | string[]) {
  return Array.isArray(value) ? value[0] ?? "" : value ?? "";
}

export default async function ProductsPage({
  searchParams,
}: ProductsPageProps) {
  const params = await searchParams;
  const query = readParam(params.q);
  const categoryId = readParam(params.category);
  const language = await getServerLanguage();
  const messages = getMessages(language);
  const [categories, products] = await Promise.all([
    getActiveCategories(),
    searchActiveProducts({
      query: query || undefined,
      categoryId: categoryId || undefined,
    }),
  ]);

  return (
    <div className="space-y-6">
      <section className="section-shell">
        <div className={language === "ar" ? "text-right" : "text-left"}>
          <h1 className="section-title">{messages.products.title}</h1>
          <p className="mt-3 max-w-2xl text-sm leading-7 text-slate-600">
            {messages.products.subtitle}
          </p>
        </div>

        <form className="mt-6 grid gap-3 md:grid-cols-[1fr_260px_140px]">
          <input
            type="search"
            name="q"
            defaultValue={query}
            placeholder={messages.products.searchPlaceholder}
            className="h-12 rounded-2xl border border-emerald-100 bg-white px-4 outline-none transition focus:border-primary"
          />
          <select
            name="category"
            defaultValue={categoryId}
            className="h-12 rounded-2xl border border-emerald-100 bg-white px-4 outline-none transition focus:border-primary"
          >
            <option value="">{messages.products.allCategories}</option>
            {categories.map((category) => (
              <option key={category.id} value={category.id}>
                {language === "ar" ? category.name_ar : category.name}
              </option>
            ))}
          </select>
          <button
            type="submit"
            className="rounded-2xl bg-primary px-5 py-3 text-sm font-semibold text-white transition hover:bg-[#256a2a]"
          >
            {messages.nav.search}
          </button>
        </form>
      </section>

      <section className="section-shell">
        <div className="mb-5 flex items-center justify-between gap-3">
          <p className="text-sm text-slate-500">
            {products.length} {messages.products.results}
          </p>
          {categoryId ? (
            <Link
              href={query ? `/products?q=${encodeURIComponent(query)}` : "/products"}
              className="text-sm font-semibold text-primary transition hover:text-[#256a2a]"
            >
              {messages.products.allCategories}
            </Link>
          ) : null}
        </div>

        {products.length > 0 ? (
          <div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">
            {products.map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        ) : (
          <p className="rounded-[1.75rem] border border-dashed border-emerald-100 bg-[#f7fbf7] px-5 py-6 text-sm text-slate-500">
            {messages.products.empty}
          </p>
        )}
      </section>
    </div>
  );
}
